#ifndef KERNEL_H
#define KERNEL_H

#include <cuda_runtime.h>
#include <cuda_fp16.h>

// Fixed dimensions as per specification
constexpr int N_SIZE = 6144;
constexpr int K_SIZE = 4096;

// Kernel launch helper declaration
void launch_gemm(half* A, half* B, half* C, int M, int N, int K, cudaStream_t stream);

#endif // KERNEL_H

#include "kernel.h"
#include <cuda_runtime.h>
#include <cuda_fp16.h>

// Block dimensions optimized for A800 (Ampere)
// 32x32 threads per block = 1024 threads
constexpr int BLOCK_M = 32;
constexpr int BLOCK_N = 32;
constexpr int TILE_K = 64; // Optimized tile size for shared memory

__global__ void gemm_kernel(half* A, half* B, half* C, int M, int N, int K) {
    // Thread indices
    int tx = threadIdx.x;
    int ty = threadIdx.y;

    // Global indices for M and N
    int m = blockIdx.y * blockDim.y + ty;
    int n = blockIdx.x * blockDim.x + tx;

    // Accumulator in float for precision
    float acc = 0.0f;

    // Shared memory tiles for A and B
    // A_tile: [BLOCK_M][TILE_K] = [32][64]
    // B_tile: [TILE_K][BLOCK_N] = [64][32]
    __shared__ half A_tile[BLOCK_M][TILE_K];
    __shared__ half B_tile[TILE_K][BLOCK_N];

    // Loop over K dimension in tiles
    for (int k = 0; k < K; k += TILE_K) {
        // Load A tile into shared memory
        // Each thread loads one element per iteration
        for (int i = 0; i < TILE_K; i += BLOCK_N) {
            int k_idx = k + tx + i;
            if (m < M && k_idx < K) {
                A_tile[ty][tx + i] = A[m * K + k_idx];
            } else {
                A_tile[ty][tx + i] = __float2half(0.0f);
            }
        }

        // Load B tile into shared memory
        // Each thread loads one element per iteration
        for (int i = 0; i < TILE_K; i += BLOCK_M) {
            int k_idx = k + ty + i;
            if (n < N && k_idx < K) {
                B_tile[ty + i][tx] = B[n * K + k_idx];
            } else {
                B_tile[ty + i][tx] = __float2half(0.0f);
            }
        }

        // Synchronize to ensure data is loaded before computation
        __syncthreads();

        // Compute partial dot product for this tile
        #pragma unroll
        for (int k_idx = 0; k_idx < TILE_K; ++k_idx) {
            acc += __half2float(A_tile[ty][k_idx]) * __half2float(B_tile[k_idx][tx]);
        }

        // Synchronize before loading next tile
        __syncthreads();
    }

    // Store result with boundary check
    if (m < M && n < N) {
        C[m * N + n] = __float2half(acc);
    }
}

void launch_gemm(half* A, half* B, half* C, int M, int N, int K, cudaStream_t stream) {
    // Grid dimensions
    // N is fixed at 6144, BlockN is 32 -> GridX = 192
    // M is variable, BlockM is 32 -> GridY = ceil(M / 32)
    dim3 block(BLOCK_N, BLOCK_M);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    gemm_kernel<<<grid, block, 0, stream>>>(A, B, C, M, N, K);
}

#include <torch/extension.h>
#include <torch/cuda.h>
#include <c10/cuda/CUDAGuard.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdexcept>
#include <string>
#include "kernel.h"

// Forward declaration for the run function
torch::Tensor run(torch::Tensor A, torch::Tensor B, torch::Tensor C);

// PyTorch extension module definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Optimized GEMM Kernel for A800 (N=6144, K=4096)");
}

torch::Tensor run(torch::Tensor A, torch::Tensor B, torch::Tensor C) {
    // Validate device
    TORCH_CHECK(A.device().is_cuda(), "Input A must be on CUDA device");
    TORCH_CHECK(B.device().is_cuda(), "Input B must be on CUDA device");
    TORCH_CHECK(C.device().is_cuda(), "Output C must be on CUDA device");
    TORCH_CHECK(A.device() == B.device(), "Inputs A and B must be on the same device");
    TORCH_CHECK(A.device() == C.device(), "All tensors must be on the same device");

    // Validate dtype
    TORCH_CHECK(A.dtype() == at::kHalf, "Input A must be float16");
    TORCH_CHECK(B.dtype() == at::kHalf, "Input B must be float16");
    TORCH_CHECK(C.dtype() == at::kHalf, "Output C must be float16");

    // Validate shapes
    int M = A.size(0);
    int K_A = A.size(1);
    int N_B = B.size(0);
    int K_B = B.size(1);
    int M_C = C.size(0);
    int N_C = C.size(1);

    TORCH_CHECK(K_A == K_SIZE, "A's K dimension must be " + std::to_string(K_SIZE));
    TORCH_CHECK(N_B == N_SIZE, "B's N dimension must be " + std::to_string(N_SIZE));
    TORCH_CHECK(K_B == K_SIZE, "B's K dimension must be " + std::to_string(K_SIZE));
    TORCH_CHECK(M_C == M, "C's M dimension must match A's M dimension");
    TORCH_CHECK(N_C == N_SIZE, "C's N dimension must be " + std::to_string(N_SIZE));
    TORCH_CHECK(A.is_contiguous(), "Input A must be contiguous");
    TORCH_CHECK(B.is_contiguous(), "Input B must be contiguous");
    TORCH_CHECK(C.is_contiguous(), "Output C must be contiguous");
    TORCH_CHECK(M > 0, "M dimension must be greater than 0");

    // Get raw pointers
    half* A_ptr = reinterpret_cast<half*>(A.data_ptr<at::Half>());
    half* B_ptr = reinterpret_cast<half*>(B.data_ptr<at::Half>());
    half* C_ptr = reinterpret_cast<half*>(C.data_ptr<at::Half>());

    // Get current CUDA stream using correct PyTorch API
    int device_index = A.device().index();
    cudaStream_t stream = c10::cuda::getCurrentCUDAStream(device_index);

    // Launch kernel
    launch_gemm(A_ptr, B_ptr, C_ptr, M, N_SIZE, K_SIZE, stream);

    // Check for kernel launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel launch failed: ") + cudaGetErrorString(err));
    }

    // Synchronize to ensure completion
    err = cudaStreamSynchronize(stream);
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA stream synchronization failed: ") + cudaGetErrorString(err));
    }

    return C;
}
